content:
game_map:
    //save
    if $data.game_map.inHouse:
        set data.game_map.inHouse false
        run hideButtons greyed
    clear_dialog
    if (!= $stats.actions.value 0):
        play music ourlovelyladyverse
    else:
        stop music
    if (!= $data.game_map.inMap true):
        set data.game_map.inMap true
        run hideButtons hidden
        run transition_black game_map
    //set_screen game_map
    run game_prompts

game_map_loadButtons:
// INTRO //
    // INTRO_WEAPON
    if (&& (objective_started? intro weapon) (== $stats.day.value 1)):
        if $data.game_map.inPrompts:
            set_button button_intro_weapon greyed
        else:
            set_button button_intro_weapon true
    // INTRO_BLUEHILLS
    if (&& (objective_started? intro bluehills) (== $stats.day.value 1)):
        if $data.game_map.inPrompts:
            set_button button_intro_bluehills greyed
        else:
            set_button button_intro_bluehills true

// HRT //
    // NKVD
    if (&& (objective_started? hrt gic) (> $stats.actions.value 2) (== $stats.day.value 2)):
        if $data.game_map.inPrompts:
            set_button button_nkvd greyed
        else:
            set_button button_nkvd true
    // PHARMACY
    if (&& (objective_started? hrt pharmacy) (!= (objective_completed? hrt pharmacy) true) (>= $stats.day.value $data.global.hrt_nextStageDay) (!= (objective_completed? hrt hrt) true)):
        if $data.game_map.inPrompts:
            set_button button_pharmacy greyed
        else:
            set_button button_pharmacy true
    // KEEPER                                    
    if (&& (objective_started? hrt keeper) (> $stats.actions.value 2)):
        if $data.game_map.inPrompts:
            set_button button_keeper greyed
        else:
            set_button button_keeper true 
    // PHARMACY (ALT)
    if (&& (== (objective_started? hrt pharmacyReturn) true) (!= (objective_completed? hrt pharmacyReturn) true) (>= $stats.day.value $data.global.hrt_nextStageDay) (!= (objective_completed? hrt hrt) true)):
        if $data.game_map.inPrompts:
            set_button button_pharmacy greyed
        else:
            set_button button_pharmacy true       
    // NKVD (ALT)  
    if (&& (objective_started? hrt private) (!= (objective_completed? hrt private) true) (> $stats.actions.value 2)):
        if $data.game_map.inPrompts:
            set_button button_nkvd greyed
        else:
            set_button button_nkvd true   
    // DEALER                                              
    if (&& (objective_started? hrt dealer) (<= $stats.actions.value 2) (!= (objective_completed? hrt hrt) true)):
        if $data.game_map.inPrompts:
            set_button button_dealer greyed
        else:
            set_button button_dealer true

// SINNER //
    // APARTMENT
    if (&& (quest_started? sinner) (objective_started? sinner apartment) (<= $stats.actions.value 1) (== $stats.day.value 2)):
        if $data.game_map.inPrompts:
            set_button button_apartment greyed
        else:
            set_button button_apartment true
    if (&& (quest_started? sinner) (objective_started? sinner apartment) (== $stats.day.value 3)):
        complete_quest sinner sinnerFailure
    // ARCHIVE                                                                
    if (&& (objective_started? sinner archive) (== $stats.day.value 3)):
        if $data.game_map.inPrompts:
            set_button button_archive greyed
        else:
            set_button button_archive true
    if (&& (objective_started? sinner archive) (== $stats.day.value 4)):
        complete_quest sinner sinnerFailure
    // WOODS  
    if (&& (objective_started? sinner woods) (> $stats.actions.value 4) (== $stats.day.value 4)):
        if $data.game_map.inPrompts:
            set_button button_woods greyed
        else:
            set_button button_woods true

// WRITER //
    // INTERVIEW_WEAPON
    if (&& (objective_started? writer interview) (== $stats.day.value 2) (!= $data.interview.weaponInterviewed true)):
        if $data.game_map.inPrompts:
            set_button button_interview greyed
        else:
            set_button button_interview true
    // WRITER_ONE
    if (&& (objective_started? writer writerOne) (has_item? article) (== $stats.day.value 2)):
        if $data.game_map.inPrompts:
            set_button button_writer_one greyed
        else:
            set_button button_writer_one true
    // WRITER_TWO
    if (&& (objective_started? writer writerTwo) (== $stats.day.value 3)):
        if $data.game_map.inPrompts:
            set_button button_writer_two greyed
        else:
            set_button button_writer_two true 
    // WRITER_LATE
    if (&& (&& (|| (objective_completed? writer article) (objective_started? writer article)) (&& (!= (quest_completed? writer) true) (!= (objective_started? writer fiction) true) (!= (objective_completed? writer fiction) true))) (== $stats.day.value 3) (!= (quest_succeeded? writer) true) (!= $data.writer.visitedLate true)):
        set data.gamemap.writerLate true
        if $data.game_map.inPrompts:
            set_button button_writer_late greyed
        else:
            set_button button_writer_late true

// WEAPON //
    // CAVE
    if (&& (objective_started? weapon parsnip) (!= (quest_completed? weapon) true)):
        if $data.game_map.inPrompts:
            set_button button_cave greyed
        else:
            set_button button_cave true  

// CRYPTO //
    // SHEEP
    if (&& (! $data.global.cryptoSheepDone true) (>= $stats.money.value 1) (== $stats.day.value 2)):
        if $data.game_map.inPrompts:
            set_button button_sheep greyed
        else:
            set_button button_sheep true
    // BRIDGE
    if (&& (! $data.global.cryptoBridgeDone 1) (>= $stats.money.value 1) (== $stats.day.value 3)):
        if $data.game_map.inPrompts:
            set_button button_bridge greyed
        else:
            set_button button_bridge true
    // EIFFEL
    if (&& (! $data.global.cryptoEiffelDone 2) (>= $stats.money.value 1) (== $stats.day.value 4)):
        if $data.game_map.inPrompts:
            set_button button_eiffel greyed
        else:
            set_button button_eiffel true 

// COMET //
    // COMET
    if (&& (== $stats.actions.value 1) (== $stats.day.value 3)):
        if $data.game_map.inPrompts:
            set_button button_comet greyed
        else:
            set_button button_comet true

// DAWNSIGHT //
    // CHURCH
    if (&& (!= (quest_completed? church) true) (> $stats.actions.value 2) (!= $stats.day.value 1)):
        if $data.game_map.inPrompts:
            set_button button_church greyed
        else:
            set_button button_church true
    // SHRINE 
    if (&& (quest_started? dawnsight) (! (quest_succeeded? dawnsight)) (! $data.dawnsight.spokeToDawnsight true) (! $data.dawnsight.prayedToday true)):
        if $data.game_map.inPrompts:
            set_button button_shrine greyed
        else:
            set_button button_shrine true

// LANDLADY // 
    // LANDLADY
    if (&& (quest_started? landlady) (!= (quest_succeeded? landlady) true) (<= $stats.actions.value 2)):
        if $data.game_map.inPrompts:
            set_button button_landlady greyed
        else:
            set_button button_landlady true

// BLUEHILLS //
    // PARK
    if (&& (! $data.global.visitedPark) (!= $stats.day.value 1)):
        if $data.game_map.inPrompts:
            set_button button_park greyed
        else:
            set_button button_park true
    // MEMORIAL
    if (&& (! $data.global.visitedMemorial) (!= $stats.day.value 1)):
        if $data.game_map.inPrompts:
            set_button button_memorial greyed
        else:
            set_button button_memorial true
    // MOVIE
    if (&& (! $data.global.visitedMovieTheater) (!= $stats.day.value 1)):
        if $data.game_map.inPrompts:
            set_button button_movie greyed
        else:
            set_button button_movie true
    // CRYPTIDS
    if (&& (! $data.cryptids.cryptidsDone) (> $stats.day.value 1)):
        if $data.game_map.inPrompts:
            set_button button_cryptids greyed
        else:
            set_button button_cryptids true  
    // RAVEN
    if (&& (! $data.raven.met) (objective_started? fixHouse raven) (!= $stats.day.value 1) (!= (quest_succeeded? fixHouse true)) (!= (has_item? hammer) true)):
        if $data.game_map.inPrompts:
            set_button button_raven greyed
        else:
            set_button button_raven true  
    // PRIDE       
    if (&& (== $stats.day.value 4) (!= $data.global.prideAttended true)):
        if $data.game_map.inPrompts:
            set_button button_pride greyed
        else:
            set_button button_pride true 
    // HOUSESNAKE
    if (&& (!= $data.houseSnake.fed true) (!= (objective_started? houseSnake boneman) true) (!= $stats.day.value 1)):
        if $data.game_map.inPrompts:
            set_button button_houseSnake greyed
        else:
            set_button button_houseSnake true
    // PERVERT
    if (&& (> $data.pervert.talkCount 0) (!= $stats.day.value 1)):
        if $data.game_map.inPrompts:
            set_button button_pervert greyed
        else:
            set_button button_pervert true

// SHOP //
    // SHOP
    if (&& (> $stats.actions.value 0) (!= $stats.day.value 1)):
        if $data.game_map.inPrompts:
            set_button button_shop greyed
        else:
            set_button button_shop true

// HOME //
    // HOME
    if (!= $stats.day.value 1):
        if $data.game_map.inPrompts:
            set_button button_home greyed
        else:
            set_button button_home true
